check.command:
sh -c 'dest=$(sqlplus -s / as sysdba <<"SQL" 2>/dev/null | awk "NF { line=\$0 } END { gsub(/^[[:space:]]+|[[:space:]]+$/, \"\", line); print line }"
set heading off feedback off pages 0 verify off echo off
select value from v$parameter where name='"'"'diagnostic_dest'"'"';
exit
SQL
); dir=${dest%/}/diag; mode=$(stat -c %a "$dir" 2>/dev/null || stat -f %Lp "$dir" 2>/dev/null || true); case "$mode" in [0-7]00|[0-7]000) printf Compliant;; esac'
